import React, { useState } from 'react';
import './App.css';

const inputStyle = {
  padding: '12px',
  borderRadius: '8px',
  border: '1px solid #ddd',
  outline: 'none'
};

function App() {
  const [showAuth, setShowAuth] = useState(false);
  const [isLogin, setIsLogin] = useState(true);
  const [view, setView] = useState('home');
  const [activeTab, setActiveTab] = useState('home'); 
  const [selectedItem, setSelectedItem] = useState(null);
  const [isVerified] = useState(false);
  const [userName] = useState('');

  const items = [
    { id: 1, name: "Raket Yonex Astrox 100 ZZ", price: "50.000", category: "Badminton", img: "/astrox.jpg", desc: "Kondisi 95% mulus, senar baru ditarik 28 lbs. Cocok untuk pemain tipe menyerang.", owner: "Jordan", location: "Jakarta Barat" },
    { id: 2, name: "Sepatu Bola Adidas F50", price: "120.000", category: "Football", img: "/f50.jpg", desc: "Size 42. Ringan banget, enak buat lari kencang. Baru dipakai 2 kali di lapangan rumput.", owner: "Gilbert", location: "Tangerang" },
    { id: 3, name: "Dumbbell 10Kg", price: "30.000", category: "Fitness", img: "/dumbbell.jpg", desc: "Bahan besi solid, grip karet tidak licin. Ada sepasang (2 pcs).", owner: "Raymond", location: "Jakarta Selatan" },
  ];

  const handleSewaClick = (item) => {
    setSelectedItem(item);
    setView('detail');
  };

  const handleBack = () => {
    setView('home');
    setSelectedItem(null);
  };

  return (
    <>
      {/* Modal Authentication */}
      {showAuth && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 }}>
          <div style={{ backgroundColor: 'white', padding: '30px', borderRadius: '15px', width: '350px', position: 'relative' }}>
            <button onClick={() => setShowAuth(false)} style={{ position: 'absolute', top: '10px', right: '10px', border: 'none', background: 'none', cursor: 'pointer', fontWeight: 'bold' }}>X</button>
            <h2 style={{ textAlign: 'center', color: '#333' }}>{isLogin ? 'Login' : 'Daftar GearShare'}</h2>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px', marginTop: '20px' }}>
              {!isLogin && <input type="text" placeholder="Nama Lengkap" style={inputStyle} />}
              <input type="email" placeholder="Email" style={inputStyle} />
              <input type="password" placeholder="Password" style={inputStyle} />
              <button style={{ padding: '12px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' }}>
                {isLogin ? 'Masuk' : 'Buat Akun'}
              </button>
              <p style={{ textAlign: 'center', fontSize: '14px' }}>
                {isLogin ? "Belum punya akun?" : "Sudah punya akun?"}
                <span onClick={() => setIsLogin(!isLogin)} style={{ color: '#007bff', cursor: 'pointer', fontWeight: 'bold', marginLeft: '5px' }}>
                  {isLogin ? 'Daftar' : 'Login'}
                </span>
              </p>
            </div>
          </div>
        </div>
      )}

      <div style={{ backgroundColor: '#f8f9fa', minHeight: '100vh', fontFamily: "'Segoe UI', sans-serif" }}>
        {/* Navbar */}
        <nav style={{ backgroundColor: '#ffffff', padding: '10px 60px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 2px 10px rgba(0,0,0,0.05)', position: 'sticky', top: 0, zIndex: 100 }}>
          <h1 onClick={() => { setView('home'); setActiveTab('home') }} style={{ color: '#007bff', margin: 0, fontSize: '24px', fontWeight: '800', cursor: 'pointer' }}>GEAR<span style={{ color: '#333' }}>SHARE</span></h1>

          {/* Menu Navigasi Tengah */}
          <div style={{ display: 'flex', gap: '40px' }}>
            {['home', 'products', 'guide', 'about us'].map((tab) => (
              <span
                key={tab}
                onClick={() => { setActiveTab(tab); setView('home') }}
                style={{
                  cursor: 'pointer', fontWeight: '600', textTransform: 'capitalize',
                  color: activeTab === tab ? '#007bff' : '#666',
                  borderBottom: activeTab === tab ? '2px solid #007bff' : 'none',
                  paddingBottom: '5px', transition: '0.3s'
                }}
              >
                {tab}
              </span>
            ))}
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            {isVerified ? (
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <span style={{ color: '#28a745', fontSize: '13px', fontWeight: 'bold' }}>✓ Terverifikasi</span>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer', padding: '5px 12px', backgroundColor: '#f1f3f5', borderRadius: '25px' }}>
                  <div style={{ width: '30px', height: '30px', backgroundColor: '#007bff', borderRadius: '50%', color: 'white', display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: 'bold', fontSize: '14px' }}>
                    {userName ? userName.charAt(0).toUpperCase() : 'U'}
                  </div>
                  <span style={{ fontWeight: '600', color: '#333', fontSize: '14px' }}>{userName || 'User'}</span>
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', gap: '15px' }}>
                <button onClick={() => { setIsLogin(true); setShowAuth(true) }} style={{ background: 'none', border: 'none', fontWeight: '600', color: '#666', cursor: 'pointer' }}>Masuk</button>
                <button onClick={() => { setIsLogin(false); setShowAuth(true) }} style={{ backgroundColor: '#007bff', color: 'white', padding: '10px 20px', borderRadius: '25px', border: 'none', fontWeight: 'bold', cursor: 'pointer' }}>Daftar</button>
              </div>
            )}
          </div>
        </nav>

        <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '40px 20px' }}>

          {view === 'home' && (
            <>
              {/* Hero Section */}
              {activeTab === 'home' && (
                <div style={{
                  textAlign: 'center', padding: '100px 20px', marginBottom: '60px',
                  background: 'linear-gradient(rgba(0, 123, 255, 0.9), rgba(0, 86, 179, 0.95)), url("https://images.unsplash.com/photo-1517836357463-d25dfeac3438?auto=format&fit=crop&q=80&w=1500") center/cover',
                  borderRadius: '40px', color: 'white', boxShadow: '0 20px 40px rgba(0,123,255,0.2)'
                }}>
                  <div style={{ maxWidth: '800px', margin: '0 auto' }}>
                    <h1 style={{ fontSize: '56px', fontWeight: '900', marginBottom: '20px', lineHeight: '1.1', letterSpacing: '-1px' }}>
                      Gear Up, <br /> <span style={{ color: '#ffc107' }}>Pay Less.</span>
                    </h1>
                    <p style={{ fontSize: '20px', opacity: 0.9, maxWidth: '550px', margin: '0 auto', lineHeight: '1.6', fontWeight: '400' }}>
                      Sewa perlengkapan olahraga kualitas pro dari tetanggamu. Hemat biaya, maksimal performa.
                    </p>
                    <div style={{ marginTop: '40px', display: 'flex', gap: '15px', justifyContent: 'center' }}>
                      <button onClick={() => setActiveTab('products')} style={{ padding: '16px 40px', backgroundColor: 'white', color: '#007bff', border: 'none', borderRadius: '15px', fontWeight: '800', fontSize: '16px', cursor: 'pointer' }}>
                        Cari Alat Sekarang
                      </button>
                      <button onClick={() => setActiveTab('guide')} style={{ padding: '16px 40px', backgroundColor: 'transparent', color: 'white', border: '2px solid rgba(255,255,255,0.3)', borderRadius: '15px', fontWeight: '700', fontSize: '16px', cursor: 'pointer' }}>
                        Cara Kerja
                      </button>
                    </div>
                  </div>
                </div>
              )}

              {/* Halaman Guide */}
              {activeTab === 'guide' && (
                <div style={{ padding: '20px', maxWidth: '900px', margin: '0 auto' }}>
                  <div style={{ textAlign: 'center', marginBottom: '50px' }}>
                    <h1 style={{ fontSize: '36px', fontWeight: '800' }}>Panduan Rental di <span style={{ color: '#007bff' }}>GearShare</span></h1>
                    <p style={{ color: '#666' }}>Semua yang perlu lu tau biar transaksi aman dan nyaman.</p>
                  </div>
                  <div style={{ display: 'grid', gap: '30px' }}>
                    <div style={{ display: 'flex', gap: '25px', backgroundColor: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 5px 15px rgba(0,0,0,0.05)' }}>
                      <div style={{ backgroundColor: '#007bff', color: 'white', minWidth: '50px', height: '50px', borderRadius: '50%', display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: 'bold', fontSize: '20px' }}>1</div>
                      <div><h3>Pilih Barang & Durasi</h3><p style={{ color: '#555', lineHeight: '1.6' }}>Cari alat olahraga di katalog. Tentukan durasi sewa, harga bakal muncul otomatis.</p></div>
                    </div>
                    <div style={{ display: 'flex', gap: '25px', backgroundColor: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 5px 15px rgba(0,0,0,0.05)' }}>
                      <div style={{ backgroundColor: '#ffc107', color: 'white', minWidth: '50px', height: '50px', borderRadius: '50%', display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: 'bold', fontSize: '20px' }}>2</div>
                      <div><h3>Verifikasi Identitas</h3><p style={{ color: '#555', lineHeight: '1.6' }}>Verifikasi KTP untuk jaminan keamanan antar pengguna GearShare.</p></div>
                    </div>
                    <div style={{ display: 'flex', gap: '25px', backgroundColor: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 5px 15px rgba(0,0,0,0.05)' }}>
                      <div style={{ backgroundColor: '#28a745', color: 'white', minWidth: '50px', height: '50px', borderRadius: '50%', display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: 'bold', fontSize: '20px' }}>3</div>
                      <div><h3>Chat & COD</h3><p style={{ color: '#555', lineHeight: '1.6' }}>Janjian sama pemilik buat COD, cek barang, dan langsung olahraga!</p></div>
                    </div>
                  </div>
                </div>
              )}

              {/* Halaman Products */}
              {(activeTab === 'products' || activeTab === 'home') && (
                <>
                  <div style={{ marginBottom: '30px', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
                    <div>
                      <h2 style={{ color: '#212529', fontSize: '28px', margin: 0 }}>{activeTab === 'products' ? 'Katalog Produk' : 'Rekomendasi Untukmu'}</h2>
                      <p style={{ color: '#6c757d', margin: '5px 0 0 0' }}>Kualitas terjamin untuk performa maksimal.</p>
                    </div>
                  </div>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '30px' }}>
                    {items.map(item => (
                      <div key={item.id} style={{ backgroundColor: '#fff', borderRadius: '20px', overflow: 'hidden', boxShadow: '0 10px 20px rgba(0,0,0,0.05)', border: '1px solid #f1f1f1' }}>
                        <img src={item.img} alt={item.name} style={{ width: '100%', height: '200px', objectFit: 'cover' }} />
                        <div style={{ padding: '25px' }}>
                          <span style={{ fontSize: '12px', color: '#007bff', fontWeight: '800' }}>{item.category}</span>
                          <h3 style={{ fontSize: '20px', margin: '10px 0' }}>{item.name}</h3>
                          <p style={{ fontSize: '20px', fontWeight: '800' }}>Rp {item.price} / hari</p>
                          <button onClick={() => handleSewaClick(item)} style={{ width: '100%', marginTop: '20px', padding: '14px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold' }}>Sewa Sekarang</button>
                        </div>
                      </div>
                    ))}
                  </div>
                </>
              )}

              {/* Halaman About Us */}
              {activeTab === 'about us' && (
                <div style={{ backgroundColor: 'white', padding: '50px', borderRadius: '25px', textAlign: 'center' }}>
                  <h2 style={{ fontSize: '36px' }}>Tentang GearShare</h2>
                  <p style={{ fontSize: '18px', color: '#666', lineHeight: '1.8' }}>Platform peer-to-peer rental alat olahraga terpercaya.</p>
                </div>
              )}
            </>
          )}

          {/* Bagian Detail */}
          {view === 'detail' && (
            <div style={{ backgroundColor: '#fff', padding: '40px', borderRadius: '25px', boxShadow: '0 10px 40px rgba(0,0,0,0.1)', display: 'flex', gap: '50px' }}>
              <div style={{ flex: 1 }}>
                <button onClick={handleBack} style={{ marginBottom: '20px', border: 'none', background: '#f1f1f1', padding: '10px 20px', borderRadius: '8px', cursor: 'pointer' }}>← Kembali</button>
                <img src={selectedItem.img} alt={selectedItem.name} style={{ width: '100%', borderRadius: '20px' }} />
              </div>
              <div style={{ flex: 1.5 }}>
                <h2 style={{ fontSize: '36px' }}>{selectedItem.name}</h2>
                <p style={{ fontSize: '28px', fontWeight: '800', color: '#007bff' }}>Rp {selectedItem.price} / hari</p>
                <p>{selectedItem.desc}</p>
                <button onClick={() => alert(`Pesanan Berhasil!`)} style={{ width: '100%', padding: '18px', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '15px', fontWeight: 'bold' }}>Konfirmasi & Chat Pemilik</button>
              </div>
            </div>
          )}
        </div>
      </div>
    </>
  );
}

export default App;
